import type { StageInput, StageOutput, StageRuntime } from '../contracts.js';

export async function runStage(input: StageInput, runtime: StageRuntime): Promise<StageOutput> {
  const domain = input.domain as Record<string, unknown>;
  const rawInput = domain['inputs.initial_user_text'];

  let plan: string | undefined;
  let seats: number | undefined;
  let region: string | undefined;

  if (typeof rawInput === 'string') {
    try {
      const parsed = JSON.parse(rawInput) as Record<string, unknown>;
      if (typeof parsed.plan === 'string') plan = parsed.plan;
      if (typeof parsed.seats === 'number') seats = parsed.seats;
      if (typeof parsed.region === 'string') region = parsed.region;
    } catch {
      // Ignore parse errors, fields remain undefined
    }
  }

  const pricingTable: Record<string, { base_usd: number; seat_rate_usd: number }> = {
    starter: { base_usd: 40, seat_rate_usd: 5 },
    pro: { base_usd: 100, seat_rate_usd: 7 },
    enterprise: { base_usd: 500, seat_rate_usd: 12 },
  };

  const regionMultiplierTable: Record<string, number> = {
    us: 1,
    eu: 1.2,
    apac: 1.1,
  };

  const pricing = plan ? pricingTable[plan] : undefined;
  const base_usd = pricing ? pricing.base_usd : 0;
  const seat_rate_usd = pricing ? pricing.seat_rate_usd : 0;
  const seatCount = seats ?? 0;
  const subtotal_usd = base_usd + seatCount * seat_rate_usd;
  const regionMultiplier = region ? (regionMultiplierTable[region] ?? 1) : 1;
  const total_usd = Math.round(subtotal_usd * regionMultiplier);
  const priced_at = runtime.now();

  const resultObj = {
    stage: 'calculate_fee',
    plan: plan ?? '',
    seats: seatCount,
    region: region ?? '',
    base_usd,
    seat_rate_usd,
    subtotal_usd,
    region_multiplier: regionMultiplier,
    total_usd,
    currency: 'USD',
    priced_at,
  };

  const itemsObj = [
    `plan:${resultObj.plan}`,
    `seats:${resultObj.seats}`,
    `total_usd:${resultObj.total_usd}`,
  ];

  return {
    result_json: JSON.stringify(resultObj),
    items_json: JSON.stringify(itemsObj),
    digest: '',
  };
}
